SELECT FROM bluenote_feed.feed_note_index WHERE item_status = 'VISIBLE' AND visibility = 'PUBLIC' AND note_status = 'PUBLISHED' AND author_id IN
#{authorId}
ORDER BY author_id ASC, published_at DESC, note_id DESC LIMIT #{limitPerAuthor}

mapper.update:
UPDATE bluenote_feed.feed_note_index
SET visibility = #{visibility},
    note_status = #{noteStatus},
    item_status = #{itemStatus},
    updated_at = #{updatedAt}
WHERE note_id = #{noteId}
